$PR_NUMBER = "49"
$TIMEOUT = 900
$INTERVAL = 30
$ELAPSED = 0

Write-Host "Waiting for Copilot coding agent to finish and CI checks to appear..."

while ($ELAPSED -lt $TIMEOUT) {
    # Check if Copilot agent is still running
    $runs = gh run list -R $REPO --branch $BRANCH --json databaseId,name,status,conclusion --limit 10 2>$null | ConvertFrom-Json
    $copilotRun = $runs | Where-Object { $_.name -eq "Running Copilot cloud agent" }

    if ($copilotRun -and $copilotRun.status -ne "in_progress" -and $copilotRun.status -ne "queued") {
        Write-Host "Copilot agent completed with status: $($copilotRun.status), conclusion: $($copilotRun.conclusion)"
    }

    # Check for CI checks on the PR
    $checks = gh pr checks $PR_NUMBER -R $REPO --json name,state,bucket 2>$null
    if ($checks -and $checks -ne "no checks reported on the 'copilot/check-full-pipeline-validation' branch") {
        Write-Host "CI checks found!"
        Write-Host $checks
        break
    }

    # Check for action_required runs
    $actionRequired = $runs | Where-Object { $_.status -eq "action_required" }
    if ($actionRequired) {
        Write-Host "Found action_required runs!"
        $actionRequired | ForEach-Object { Write-Host "  Run $($_.databaseId): $($_.name)" }
        break
    }

    Write-Host "Still waiting... (${ELAPSED}s) Copilot agent status: $($copilotRun.status)"
    Start-Sleep -Seconds $INTERVAL
    $ELAPSED += $INTERVAL
}

